import { Injectable, Logger } from '@nestjs/common';

import { AlgoliaService } from '@modules/algolia/algolia.service';
import { PromotionalProductsService as DBPromotionalProductsService } from '@modules/db/promotional-products/promotional-products.service';
import { StylesService } from '@modules/db/styles/styles.service';
import { PromotionalProductsResponseDto } from '@modules/rest/promotional-products/dto/promotional-products-response.dto';
import { TrendingProductsService } from '@modules/rest/trending-products/trending-products.service';

import { shuffleArray } from '@utils/array.util';
import { assignRandomColorToProduct } from '@utils/random-color-picker.util';

import { IRelatedProduct } from '@interfaces/related-product.interface';

@Injectable()
export class PromotionalProductsService {
	private readonly logger = new Logger(PromotionalProductsService.name);

	constructor(
		private readonly trendingProductsService: TrendingProductsService,
		private readonly dbPromotionalProductsService: DBPromotionalProductsService,
		private readonly algoliaService: AlgoliaService,
		private readonly styleService: StylesService,
	) {}

	async getPromotionalProducts(
		categoryId?: number,
		limit = 20,
	): Promise<PromotionalProductsResponseDto> {
		try {
			const halfLimit = Math.floor(limit / 2);

			const dbPromotionalProducts = categoryId
				? await this.dbPromotionalProductsService.getProductsByCategory({
						categoryId,
						limit: halfLimit,
					})
				: await this.dbPromotionalProductsService.getRandomProducts(halfLimit);

			const promotionalProducts: IRelatedProduct[] = [];

			if (dbPromotionalProducts.length > 0) {
				const productIds = dbPromotionalProducts.map((p) => String(p.product_id));

				try {
					const algoliaHits = await this.algoliaService.getMultipleObjects(productIds);

					const listOfActiveProducts = await this.styleService.getStylesInStockByIds({
						styleIds: productIds.map((id) => Number(id)),
					});

					for (const hit of algoliaHits) {
						if (hit.product_id) {
							const relatedProduct = this.algoliaService.mapHitToRelatedProduct(
								hit,
								null,
							);
							const productWithRandomColor = assignRandomColorToProduct(
								relatedProduct,
								hit.colors,
							);
							if (
								listOfActiveProducts.some(
									(style) => style.style_id === productWithRandomColor.style_id,
								)
							) {
								promotionalProducts.push(productWithRandomColor);
							}
						}
					}

					this.logger.debug(
						`Verified ${promotionalProducts.length} promotional products exist in Algolia out of ${dbPromotionalProducts.length} requested`,
					);
				} catch (error) {
					this.logger.error(
						`Error verifying promotional products in Algolia: ${(error as Error).message}`,
					);
				}
			}

			const remainingLimit = limit - promotionalProducts.length;
			let trendingProducts: IRelatedProduct[] = [];

			if (remainingLimit > 0 && categoryId) {
				const trendingResult =
					await this.trendingProductsService.getTrendingProductsByCategory({
						categoryId,
						excludeProductIds: promotionalProducts.map((p) => p.style_id),
						limit: remainingLimit,
					});
				trendingProducts = trendingResult.trendingProducts;
			}

			const allProducts = [...trendingProducts, ...promotionalProducts];
			const shuffledProducts = shuffleArray(allProducts);

			return {
				categoryId: categoryId ?? -1,
				products: shuffledProducts,
				totalCount: shuffledProducts.length,
				trendingCount: trendingProducts.length,
				promotionalCount: promotionalProducts.length,
			};
		} catch (error) {
			this.logger.error(
				`Error fetching promotional products${categoryId ? ` for category ${categoryId}` : ''}: ${(error as Error).message}`,
			);
			throw error;
		}
	}
}

