import { Logger } from '@nestjs/common';
import { plainToInstance } from 'class-transformer';
import {
	IsBoolean,
	IsEnum,
	IsNotEmpty,
	IsNumber,
	IsString,
	Max,
	Min,
	validateSync,
} from 'class-validator';

import { Environment } from '@interfaces/env-variables.interface';

class EnvironmentVariables {
	@IsBoolean()
	IS_COMPACT_LOGS: boolean;

	@IsBoolean()
	IS_JSON_LIKE_LOGS: boolean;

	@IsEnum(Environment)
	NODE_ENV: Environment;

	@IsNumber()
	@Min(0)
	@Max(65535)
	PORT: number;

	@IsString()
	@IsNotEmpty()
	GLOBAL_PREFIX: string;

	@IsString()
	@IsNotEmpty()
	SERVER_NAME: string;

	@IsNumber()
	@Min(0)
	@Max(60000)
	GRACEFUL_SHUTDOWN_DELAY: number;

	@IsString()
	@IsNotEmpty()
	OPENAI_API_KEY: string;

	@IsString()
	@IsNotEmpty()
	ALG_APP_ID: string;

	@IsString()
	@IsNotEmpty()
	ALG_API_KEY: string;

	@IsString()
	@IsNotEmpty()
	ALG_INDEX_NAME: string;

	@IsString()
	@IsNotEmpty()
	REDIS_URL: string;

	@IsString()
	@IsNotEmpty()
	REDIS_READ_URL: string;

	@IsString()
	@IsNotEmpty()
	ROLLBAR_ACCESS_TOKEN: string;

	@IsString()
	@IsNotEmpty()
	NEWRELIC_KEY: string;

	@IsString()
	@IsNotEmpty()
	AWS_REGION: string;

	@IsString()
	@IsNotEmpty()
	MMS_INTERNAL_BASE_URL: string;

	@IsString()
	@IsNotEmpty()
	ARTILLERY_KEY: string;

	@IsString()
	@IsNotEmpty()
	RELATED_PRODUCTS_CACHE_TTL: string;

	@IsString()
	@IsNotEmpty()
	CURATED_ADDONS_CACHE_TTL: string;

	@IsString()
	@IsNotEmpty()
	CI_BASE_URL: string;

	@IsString()
	@IsNotEmpty()
	DATABASE_URL_READ_REPLICA: string;

	@IsString()
	@IsNotEmpty()
	DATABASE_URL: string;

	@IsString()
	@IsNotEmpty()
	MMS_IMAGES_LAMBDA_HOST: string;

	@IsString()
	@IsNotEmpty()
	ALG_FBT_INDEX_NAME: string;

	@IsString()
	@IsNotEmpty()
	REDSHIFT_READ_URL: string;

	@IsNumber()
	@Min(0)
	@Max(60000)
	EXECUTION_TIME_THRESHOLD_MS: number;
}

export function validate(config: Record<string, unknown>): EnvironmentVariables {
	const logger = Logger;
	const validatedConfig = plainToInstance(EnvironmentVariables, config, {
		enableImplicitConversion: true,
	});

	const errors = validateSync(validatedConfig, {
		skipMissingProperties: false,
		forbidUnknownValues: true,
		stopAtFirstError: true,
		forbidNonWhitelisted: true,
	});

	if (errors.length > 0) {
		logger.error('Config validation error', errors);
		throw new Error(errors.toString());
	}

	return validatedConfig;
}

